const LOGO: &str = r#"
 .d8888b.  888                                      Y88b   d88P
d88P  Y88b 888                                       Y88b d88P
Y88b.      888                                        Y88o88P
 "Y888b.   888888  8888b.  888d88 8888d888 888  888    Y888P
    "Y88b. 888        "88b 888P"   888P"   888  888    d888b
      "888 888    .d888888 888     888     888  888   d88888b
Y88b  d88P Y88b.  888  888 888     888     Y88b 888  d88P Y88b
 "Y8888P"   "Y888 "Y888888 888     888      "Y88888 d88P   Y88b
                                                888
                                           Y8b d88P
                                            "Y88P"
"#;

const RAINBOW_COLORS: &[&str] = &[
    "\x1b[38;5;219m",
    "\x1b[38;5;217m",
    "\x1b[38;5;216m",
    "\x1b[38;5;229m",
    "\x1b[38;5;193m",
    "\x1b[38;5;158m",
    "\x1b[38;5;159m",
    "\x1b[38;5;153m",
    "\x1b[38;5;147m",
    "\x1b[38;5;183m",
    "\x1b[38;5;182m",
    "\x1b[38;5;218m",
];

const RESET_COLOR: &str = "\x1b[0m";

fn print_logo() {
    let lines: Vec<&str> = LOGO.lines().collect();
    for (i, line) in lines.iter().enumerate() {
        let color = RAINBOW_COLORS[i % RAINBOW_COLORS.len()];
        ax_println!("{}{}{}", color, line, RESET_COLOR);
    }
}

#[unsafe(no_mangle)]
fn main() {
    print_logo();
    xprocess::Process::new_init(axtask::current().id().as_u64() as _).build();
    xcore::fs::vfs::init_root().expect("Failed to mount vfs");
    xcore::fs::fd::init_stdio().expect("Failed to init stdio");

    let envs = [format!("ARCH={}", option_env!("ARCH").unwrap_or("unknown"))];

    let init = include_str!("init.sh");

    info!("Running init script");
    let args = ["/bin/busybox", "sh", "-c", init]
        .map(|s| s.to_string())
        .to_vec();
    let exit_code = entry::run_user_app(&args, &envs);
    info!("Init script exited with code: {:?}", exit_code);
}

use alloc::{borrow::ToOwned, string::String, sync::Arc};

use axfs_ng::FS_CONTEXT;
use axhal::arch::UspaceContext;
use axsync::Mutex;
use spin::RwLock;

use xcore::{
    fs::{fd::FD_TABLE, with_fs},
    ipc::IPC_MANAGER,
    mm::{XUserSpace, copy_from_kernel, load_app, load_file, map_trampoline, new_aspace},
    task::{XProcess, XTaskExt, XThread, add_thread_to_table, new_user_task},
};
use xprocess::{Pid, init_proc};
use xsignal::Signo;
use xutils::ctypes::AT_FDCWD;
use xvma::VmaManager;

pub fn run_user_app(args: &[String], envs: &[String]) -> Option<i32> {
    let mut uspace = new_aspace()
        .and_then(|mut it| {
            copy_from_kernel(&mut it)?;
            map_trampoline(&mut it)?;
            Ok(it)
        })
        .expect("Failed to create user address space");

    let exe_path = &args[0];
    let name = with_fs(AT_FDCWD, exe_path, |fs| {
        let loc = fs.resolve(exe_path)?;
        let name = loc.name().to_owned();
        fs.set_current_dir(loc.parent().unwrap())?;
        Ok(name)
    })
    .expect("Failed to resolve executable path");

    let (file_data, new_args) =
        load_file(None, args).unwrap_or_else(|e| panic!("Failed to load file: {}", e));
    let (entry_vaddr, ustack_top) = load_app(&mut uspace, file_data, &new_args, envs, true)
        .unwrap_or_else(|e| panic!("Failed to load user app: {}", e));

    let uctx = UspaceContext::new(entry_vaddr.into(), ustack_top, 2333);

    let mut task = new_user_task(&name, uctx, None);
    task.ctx_mut().set_page_table_root(uspace.page_table_root());

    let process_data = XProcess::new(
        exe_path.clone(),
        XUserSpace::new(Arc::new(Mutex::new(uspace)), RwLock::new(VmaManager::new())),
        Arc::default(),
        Some(Signo::SIGCHLD),
        None,
    );

    FD_TABLE
        .deref_from(&process_data.ns)
        .init_new(FD_TABLE.copy_inner());
    FS_CONTEXT
        .deref_from(&process_data.ns)
        .init_new(FS_CONTEXT.copy_inner());
    IPC_MANAGER
        .deref_from(&process_data.ns)
        .init_new(IPC_MANAGER.copy_inner());

    let tid = task.id().as_u64() as Pid;
    let process = init_proc().fork(tid).data(process_data).build();

    let thread = process
        .new_thread(tid)
        .data(XThread::new(process.data().unwrap()))
        .build();
    add_thread_to_table(&thread);

    task.init_task_ext(XTaskExt::new(thread));

    let task = axtask::spawn_task(task);

    // TODO: we need a way to wait on the process but not only the main task
    task.join()
}

use alloc::format;

use axhal::{
    mem::{MemoryAddr, PAGE_SIZE_4K, VirtAddr, virt_to_phys},
    paging::MappingFlags,
    trap::{PAGE_FAULT, register_trap_handler},
};
use axmm::PageSize;
use axtask::current;
use linux_raw_sys::general::{RLIMIT_STACK, SI_KERNEL, SIGSEGV};

use xcore::task::{XTaskExt, send_signal_process};
use xsignal::{SignalInfo, Signo};
use xuspace::is_accessing_user_memory;

fn _mm_trace(vaddr: VirtAddr, len: usize) {
    let xtask = XTaskExt::from_task(&current());
    let xprocess = xtask.xprocess();

    let aspace = xprocess.uspace().aspace.lock();

    let mut buffer = alloc::vec![0u8; len];

    match aspace.read(vaddr, &mut buffer, PageSize::Size4K) {
        Ok(()) => {
            info!(
                "Memory trace from {:#x} to {:#x} (len: {}):",
                vaddr,
                vaddr + len,
                len
            );

            for (i, chunk) in buffer.chunks(16).enumerate() {
                let addr = vaddr + i * 16;
                let mut line = format!("{:#010x}: ", addr);

                for (j, byte) in chunk.iter().enumerate() {
                    if j % 8 == 0 && j > 0 {
                        line.push(' ');
                    }
                    line.push_str(&format!("{:02x} ", byte));
                }

                while line.len() < 60 {
                    line.push(' ');
                }

                line.push('|');
                for byte in chunk {
                    if *byte >= 32 && *byte <= 126 {
                        line.push(*byte as char);
                    } else {
                        line.push('.');
                    }
                }
                line.push('|');

                info!("{}", line);
            }
        }
        Err(e) => {
            warn!("Failed to read memory at {:#x}: {:?}", vaddr, e);
        }
    }
}

#[register_trap_handler(PAGE_FAULT)]
fn handle_page_fault(vaddr: VirtAddr, access_flags: MappingFlags, is_user: bool) -> bool {
    // warn!(
    //     "Page fault at {:#x}, access_flags: {:#x?}",
    //     vaddr, access_flags
    // );
    if !is_user && !is_accessing_user_memory() {
        return false;
    }

    let xtask = XTaskExt::from_task(&current());
    let xprocess = xtask.xprocess();
    let send_sigsegv = || {
        debug!("Sending SIGSEGV");
        let _ = send_signal_process(
            xtask.thread_ref().process(),
            SignalInfo::new(Signo::from_repr(SIGSEGV as u8).unwrap(), SI_KERNEL as _),
        );
    };

    if (xcore::config::USER_STACK_TOP - xcore::config::USER_STACK_SIZE
        ..xcore::config::USER_STACK_TOP)
        .contains(&vaddr.as_usize())
    {
        // Stack extension, check rlimit
        let rlimit = &xprocess.rlimits.read()[RLIMIT_STACK];
        let size = xcore::config::USER_STACK_TOP - vaddr.as_usize();
        if size as u64 > rlimit.current {
            debug!("Stack extension, check rlimit");
            send_sigsegv();
        }
    }

    if !xprocess
        .uspace()
        .aspace
        .lock()
        .handle_page_fault(vaddr, access_flags)
    {
        warn!(
            "{} ({:?}): segmentation fault at VirtAddr: ({:#x}), PhysAddr: ({:#x}), sending SIGSEGV",
            current().id_name(),
            xtask.thread_ref(),
            vaddr,
            virt_to_phys(vaddr),
        );

        // mm_trace(VirtAddr::from_usize(0x3fffffb00), 1024);

        let _ = send_signal_process(
            xtask.thread_ref().process(),
            SignalInfo::new(Signo::from_repr(SIGSEGV as u8).unwrap(), SI_KERNEL as _),
        );
    }

    xprocess
        .uspace()
        .populate_file_pages(vaddr.align_down_4k(), PAGE_SIZE_4K)
        .map_err(|_| send_sigsegv())
        .ok();

    true
}

