    }

    fn write_page(addr: VirtAddr, buf: &[u8]) -> LinuxResult {
        unsafe {
            core::ptr::copy_nonoverlapping(buf.as_ptr(), addr.as_mut_ptr(), buf.len());
        }
        Ok(())
    }
}

