fn irq_stat() -> String {
    let mut result = String::new();

    let irq_stats = axhal::irq::irq_stat();

    for (irq_num, count) in irq_stats {
        result.push_str(&format!("{}:        {}\n", irq_num, count));
    }

    result
}

