/// A thread.
pub struct Thread {
    tid: Pid,
    process: Arc<Process>,
    data: Box<dyn Any + Send + Sync>,
}

impl Thread {
    /// The [`Thread`] ID.
    pub fn tid(&self) -> Pid {
        self.tid
    }

    /// The [`Process`] this thread belongs to.
    pub fn process(&self) -> &Arc<Process> {
        &self.process
    }

    /// The data associated with the [`Process`] this thread belongs to.
    pub fn proc_data<T: Any + Send + Sync>(&self) -> Option<&T> {
        self.process.data.downcast_ref::<T>()
    }

    /// The data associated with the [`Thread`].
    pub fn data<T: Any + Send + Sync>(&self) -> Option<&T> {
        self.data.downcast_ref::<T>()
    }

    /// The data associated with the [`Thread`] as an [`Arc`].
    pub fn data_arc<T: Any + Send + Sync>(&self) -> Option<Arc<&T>> {
        self.data.downcast_ref::<T>().map(Arc::new)
    }

    /// Exits the thread.
    ///
    /// Returns `true` if the thread was the last one in the thread group.
    pub fn exit(&self, exit_code: i32) -> bool {
        let mut tg = self.process.tg.lock();
        if !tg.group_exited {
            tg.exit_code = exit_code;
        }
        tg.threads.remove(&self.tid);
        tg.threads.is_empty()
    }
}

